export * from './helpers';
export * from './infer-type';
export * from './schema';

# @belt/tools

A TypeScript utility library providing runtime type validation, state management, and common helpers for complex frontend applications including WebGL/game loops requiring high-performance state management.

## Installation

```bash
npm install @belt/tools
# or
pnpm add @belt/tools
```

**Peer Dependencies:**
- `react` >= 18.0.0 (optional, only for state-machine hooks)

## Quick Start

### Schema Validation

```typescript
import { createModel, createType, InferType, isType } from '@belt/tools';

// Create a validated model
const UserSchema = createModel({
  id: 'number',
  name: 'string',
  email: 'string?',        // optional
  roles: 'string[]',       // array
});

type User = InferType<typeof UserSchema>;

// Parse and validate data
const user = UserSchema.parse({
  id: 1,
  name: 'John',
  roles: ['admin'],
});

// Type guard
if (isType(someValue, 'number')) {
  console.log(someValue.toFixed(2)); // TypeScript knows it's a number
}
```

### State Machine

```typescript
import { createMachine, createSlice } from '@belt/tools';

// Create a slice
const counterSlice = createSlice({
  id: 'counter',
  initial: { count: 0 },
  cache: { policy: 'session' },
  reducers: {
    increment: (state) => { state.count += 1; },
    decrement: (state) => { state.count -= 1; },
    set: (state, value: number) => { state.count = value; },
  },
});

// Create the machine
const appMachine = createMachine({
  id: 'app',
  slices: { counter: counterSlice },
  context: { userID: null },
});

// Use in React components
function Counter() {
  const { state, actions } = appMachine.useMachine('counter');

  return (
    <div>
      <span>{state.count}</span>
      <button onClick={() => actions.increment()}>+</button>
      <button onClick={() => actions.decrement()}>-</button>
    </div>
  );
}
```

### Helpers

```typescript
import {
  getProperty,
  ms,
  formatDate,
  invariant,
  tryCatch,
} from '@belt/tools';

// Deep property access
const street = getProperty(user, 'address.street');

// Time conversion
const timeout = ms('5m');  // 300000 (5 minutes in ms)

// Date formatting
const formatted = formatDate(new Date(), 'yyyy-MM-dd'); // '2025-12-28'

// Assertions
invariant(user.id, 'User ID is required');

// Safe error handling
const [error, result] = tryCatch(() => JSON.parse(data));
if (error) {
  console.error('Parse failed:', error.message);
}
```

## Modules

### Schema Module

Runtime type validation with TypeBox under the hood.

- `createType(definition)` - Create a compiled type validator
- `createModel(properties)` - Convenience function for object schemas
- `isType(value, definition)` - Type guard
- `invariantType(definition, value)` - Assertion

### State Machine Module

Redux-like state management with React hooks and Immer.

- `createMachine(config)` - Create a state machine
- `createSlice(config)` - Create a synchronous slice
- `createAsyncSlice(config)` - Create an async slice for data fetching
- Cache policies: `public`, `private`, `session`

### Helpers Module

Pure utility functions:

- Object utilities: `objectKeys`, `objectEntries`, `getProperty`, `setProperty`, `keyBy`
- Error utilities: `invariant`, `tryCatch`, `InvariantError`
- String utilities: `isString`, `assertString`, `capitalize`
- Time utilities: `ms`, `delay`, `formatDate`
- Other: `createProxy`, `maskData`, `getTypeOf`

### Type Utils Module

TypeScript utility types:

- `Writable<T>` - Remove readonly modifiers
- `Compute<T>` - Flatten intersection types
- `Paths<T>` - All dot-notation paths of object
- `PathType<T, P>` - Type at specific path
- `Falsy` - Union of falsy values
- `UnionToIntersection<T>` - Convert union to intersection

