   312вҶ’      id,
   313вҶ’      kind: SliceKind.sync,
   314вҶ’      cache,
   315вҶ’      initial,
   316вҶ’      reducers,
   317вҶ’    });
   318вҶ’  };
   319вҶ’
   320вҶ’  /**
   321вҶ’   * Factory function to create an asynchronous slice definition.
   322вҶ’   * Async slices manage state related to data fetching operations.
   323вҶ’   * @param config - The slice's configuration, including ID, the data loading function, and optional context.
   324вҶ’   * @returns A complete asynchronous slice definition.
   325вҶ’   */
   326вҶ’  export const CreateAsync: CreateAsyncSlice = (config) => {
   327вҶ’    const { load, id, context, initial, cache } = config;
   328вҶ’
   329вҶ’    return requireAll({
   330вҶ’      kind: SliceKind.async,
   331вҶ’      initial: Slices.AsyncInitialState(initial),
   332вҶ’      cache,
   333вҶ’      load,
   334вҶ’      id,
   335вҶ’      context,
   336вҶ’    });
   337вҶ’  };
   338вҶ’}
   339вҶ’
   340вҶ’export const createSlice = Slices.CreateSync;
   341вҶ’export const createSyncSlice = Slices.CreateSync;
   342вҶ’export const createAsyncSlice = Slices.CreateAsync;
