import { produce } from 'immer';

import { defineFunctionName } from '../helpers/function';
import { assertObject, getProperty, objectEntries, requireAll } from '../helpers/object-utils';
import { capitalize } from '../helpers/string-utils';

import type { AnyRecord } from '../helpers/type-utils';

import { createModel, createType } from '../schema';

import { Cache } from './cache';
import {
  type AsyncSliceState,
  type CacheStrategy,
  type CreateAsyncSlice,
  type CreateSlice,
  type MachineAction,
  type MachineReducer,
  type MachineSliceInfo,
  type MachineSlices,
  type MachineState,
  type RuntimeActionCreator,
  type SliceContext,
  SliceKind,
  type SliceReducer,
  type StringTypes,
} from './models';

export namespace Slices {
  export type SliceMapReducer = MachineReducer & { info: MachineSliceInfo };
  // prettier-ignore
  export type SliceMap = {
    reducer: SliceMapReducer;
    actionCreatorByType: { [K in StringTypes.ActionType]: RuntimeActionCreator };
    actionCreatorListBySliceKey: { [K in StringTypes.SliceKey]: RuntimeActionCreator[] };
    actionCreatorsSliceKey: { [K in StringTypes.SliceKey]: { [K: string]: RuntimeActionCreator } };
    actionTypesBySliceKey: { [K in StringTypes.SliceKey]: { [K: string]: string } };
    reducerBySliceKey: { [K: StringTypes.SliceKey]: SliceMapReducer };
    reducerByActionType: { [K in StringTypes.ActionType]: SliceMapReducer };
    actionTypeList: StringTypes.ActionType[];
  };

  /** Explicit type for sync slice model */
  export type SyncSliceModel = {
    id: string;
    kind: SliceKind.sync;
    initial: unknown;
    reducers: Record<string, SliceReducer>;
    cache: CacheStrategy;
  };

  /** Explicit type for async slice model */
  export type AsyncSliceModel = {
    id: string;
    kind: SliceKind.async;
    initial: AsyncSliceState<unknown>;
    load: (...args: any[]) => Promise<unknown>;
    context: SliceContext;
    cache: CacheStrategy;
  };

  export type SlicesMap = Omit<SliceMap, 'reducer'> & {
    info: MachineSliceInfo[];
    mergedSlicesInitialContext: SliceContext;
    mergedSlicesInitialState: AnyRecord;
  };

  export const SyncSliceModel = createModel({
    id: 'string',
    kind: { enum: [SliceKind.sync] },
    initial: 'unknown',
    reducers: { record: 'function' },
    cache: Cache.Model,
  });

  export const AsyncSliceModel = createModel({
    id: 'string',
    kind: { enum: [SliceKind.async] },
    initial: 'any',
    load: 'function',
    context: 'object',
    cache: Cache.Model,
  });

  export const AnySliceModel = createType({
    union: [SyncSliceModel, AsyncSliceModel],
  });

  export function IsSyncSliceKind(value: unknown): value is SyncSliceModel {
    assertObject(value);
    return SyncSliceModel.isValid(value);
  }

  export function IsAsyncSliceKind(value: unknown): value is AsyncSliceModel {
    assertObject(value);
    return AsyncSliceModel.isValid(value);
  }

  export const AsyncReducerNames = new Set(['load', 'success', 'fail', 'clear'] as const);

  /**
   * Maps one slice to internal machine utils
   * @param machineID
   * @param map
   * @constructor
   */
  export function MapSlice(machineID: string, map: MachineSliceInfo): SliceMap {
    const { sliceKey, slice, actionPrefix } = map;
    let reducer = null as SliceMapReducer | null;
    const actionCreatorByType = {} as SlicesMap['actionCreatorByType'];
    const reducerByActionType = {} as SlicesMap['reducerByActionType'];
    // prettier-ignore
    const actionCreatorListBySliceKey = {} as SlicesMap['actionCreatorListBySliceKey'];
    const actionCreatorsSliceKey = {} as SlicesMap['actionCreatorsSliceKey'];
    const actionTypesBySliceKey = {} as SlicesMap['actionTypesBySliceKey'];
    const actionTypeList = [] as SlicesMap['actionTypeList'];

    const namePrefix = `${machineID}${capitalize(sliceKey)}`;

    function registerAction(reducerName: StringTypes.SliceReducerName): RuntimeActionCreator {
      const actionType = `${actionPrefix}${reducerName}` as StringTypes.ActionType;

      function action(payload: unknown): MachineAction {
        return {
          type: actionType,
          payload,
        };
      }

      defineFunctionName(action, `${namePrefix}${capitalize(reducerName)}RuntimeActionCreator`);
      action.info = map;
      action.type = actionType;
      action.sliceReducerName = reducerName;
      actionCreatorByType[actionType] = action;
      actionTypeList.push(actionType);
      // prettier-ignore
      actionCreatorListBySliceKey[sliceKey] = actionCreatorListBySliceKey[sliceKey] || [];
      actionCreatorsSliceKey[sliceKey] = actionCreatorsSliceKey[sliceKey] || {};
      actionTypesBySliceKey[sliceKey] = actionTypesBySliceKey[sliceKey] || {};
      actionTypesBySliceKey[sliceKey][reducerName] = actionType;
      actionCreatorListBySliceKey[sliceKey].push(action);
      actionCreatorsSliceKey[sliceKey][reducerName] = action;
      return action;
    }

    if (IsAsyncSliceKind(slice)) {
      AsyncReducerNames.forEach((name) => {
        return registerAction(name as StringTypes.SliceReducerName);
      });

      const fn = function reducer(state = slice.initial as MachineState, action: MachineAction) {
        // prettier-ignore
        const localAction = actionCreatorByType[action.type as StringTypes.ActionType];
        if (!localAction) return state;

        const sliceReducerName = localAction.sliceReducerName;

        return produce(state, (draft) => {
          switch (sliceReducerName) {
            case 'load': {
              draft.loading = true;
              draft.failed = false;
              draft.error = null;
              return;
            }
            case 'success': {
              draft.loading = false;
              draft.loaded = true;
              draft.value = action.payload;
              return;
            }
            case 'fail': {
              const error = getProperty(action.payload, 'error', true);
              draft.loading = false;
              draft.failed = true;
              draft.error = error as string;
              return;
            }
            case 'clear': {
              return slice.initial;
            }
            default: {
              return;
            }
          }
        });
      };
      fn.info = map;
      reducer = fn;
    } else if (IsSyncSliceKind(slice)) {
      const syncSlice = slice as SyncSliceModel;
      const sliceReducersByActionTypes = new Map<string, SliceReducer>();

      objectEntries(syncSlice.reducers).forEach(([name, sliceReducer]) => {
        const { type } = registerAction(name as StringTypes.SliceReducerName);
        sliceReducersByActionTypes.set(type, sliceReducer);
      });

      const fn = function reducer(
        state = syncSlice.initial as MachineState,
        action: MachineAction,
      ) {
        const reducer = sliceReducersByActionTypes.get(action.type);
        if (!reducer) return state;
        return produce(state, (draft) => {
          return reducer(draft, action.payload);
        });
      };
      fn.info = map;
      reducer = fn;
    } else {
      AnySliceModel.parse(slice);
    }

    if (typeof reducer !== 'function') {
      throw new Error(`Failed to create reducer from slice "${sliceKey}".`);
    }

    actionTypeList.forEach((actionType) => {
      reducerByActionType[actionType] = reducer;
    });

    defineFunctionName(reducer, `${machineID}${sliceKey}Reducer`);

    return {
      reducer,
      reducerBySliceKey: { [sliceKey]: reducer },
      actionCreatorsSliceKey,
      actionCreatorListBySliceKey,
      actionCreatorByType,
      reducerByActionType,
      actionTypesBySliceKey,
      actionTypeList,
    };
  }

  /**
   * Maps multiples slices to machine internal utils
   * @param machineID
   * @param slices
   * @constructor
   */
  export function MapSlices(machineID: string, slices: MachineSlices): SlicesMap {
    const reducersMap: SlicesMap = {
      info: [],
      actionTypeList: [],
      actionTypesBySliceKey: {},
      mergedSlicesInitialContext: {},
      mergedSlicesInitialState: {},
      actionCreatorByType: {},
      reducerByActionType: {},
      reducerBySliceKey: {},
      actionCreatorListBySliceKey: {},
      actionCreatorsSliceKey: {},
    };

    const prefix = `@${machineID}/` as const;

    // prettier-ignore
    Object.entries(slices).forEach(([sliceKey, slice]) => {
      const info = {
        sliceKey: sliceKey as StringTypes.SliceKey,
        slice,
        actionPrefix: `${prefix}${slice.id}/`,
      };
      const map = MapSlice(machineID, info);
      const initial = IsSyncSliceKind(slice) ? slice.initial : AsyncInitialState(null);
      reducersMap.info.push(info);
      reducersMap.actionTypeList.push(...map.actionTypeList);
      Object.assign(reducersMap.mergedSlicesInitialContext, slice.context);
      Object.assign(reducersMap.mergedSlicesInitialState, { [sliceKey]: initial });
      Object.assign(reducersMap.actionTypesBySliceKey, map.actionTypesBySliceKey);
      Object.assign(reducersMap.actionCreatorByType, map.actionCreatorByType);
      Object.assign(reducersMap.reducerByActionType, map.reducerByActionType);
      Object.assign(reducersMap.reducerBySliceKey, map.reducerBySliceKey);
      Object.assign(reducersMap.actionCreatorsSliceKey, map.actionCreatorsSliceKey);
      Object.assign(reducersMap.actionCreatorListBySliceKey, map.actionCreatorListBySliceKey);
    });

    return reducersMap;
  }

  /**
   * Creates the standard initial state object for an async slice.
   * @param initial - Optional initial values to merge into the state.
   * @returns An object representing the default state for an async operation.
   */
  export function AsyncInitialState<T>(
    initial: AsyncSliceState<T> | null | undefined,
  ): AsyncSliceState<T> {
    return {
      loading: false,
      loaded: false,
      failed: false,
      error: null,
      value: null,
      changes: 0,
      ...initial,
    };
  }

  /**
   * Factory function to create a synchronous slice definition.
   * Sync slices manage state through pure reducer functions.
   * @param config - The slice's configuration, including ID, initial state, and reducers.
   * @returns A complete synchronous slice definition.
   */
  export const CreateSync: CreateSlice = (config) => {
    const { initial, reducers, id, cache } = config;

    return requireAll({
      id,
      kind: SliceKind.sync,
      cache,
      initial,
      reducers,
    });
  };

  /**
   * Factory function to create an asynchronous slice definition.
   * Async slices manage state related to data fetching operations.
   * @param config - The slice's configuration, including ID, the data loading function, and optional context.
   * @returns A complete asynchronous slice definition.
   */
  export const CreateAsync: CreateAsyncSlice = (config) => {
    const { load, id, context, initial, cache } = config;

    return requireAll({
      kind: SliceKind.async,
      initial: Slices.AsyncInitialState(initial),
      cache,
      load,
      id,
      context,
    });
  };
}

export const createSlice = Slices.CreateSync;
export const createSyncSlice = Slices.CreateSync;
export const createAsyncSlice = Slices.CreateAsync;

