   330вҶ’        context.assign(value);
   331вҶ’        const metadata = initialState[METADATA_FIELD_NAME] as MachineMetadata;
   332вҶ’        assertObject(metadata, 'Metadata was not provided by initialState');
   333вҶ’        initialState = {
