   335вҶ’          [METADATA_FIELD_NAME]: {
   336вҶ’            ...metadata,
   337вҶ’            userID: context.get().userID,
   338вҶ’          },
   339вҶ’        };
   340вҶ’      },
   341вҶ’    } as Machine;
   342вҶ’  }
   343вҶ’}
   344вҶ’
   345вҶ’export const createMachine = Machine.Create;
