// Accessing multiple slices
function ProcessPanel() {
  const { state: processes, actions } = appMachine.useMachine('processes');
  const { state: ui } = appMachine.useMachine('ui');

  const activeProcesses = Object.values(processes).filter(
    (p) => p.projectId === ui.activeTab
  );

  return (
    <div>
      {activeProcesses.map((process) => (
        <ProcessCard
          key={process.id}
          process={process}
          onKill={() => actions.kill(process.id)}
        />
      ))}
    </div>
  );
}

// Using async slice - handles loading/error states
function FeatureBoard({ projectPath }: { projectPath: string }) {
  const { state, actions } = appMachine.useMachine('features');

  // Trigger load on mount or path change
  React.useEffect(() => {
    actions.load(projectPath);
  }, [projectPath]);

  if (state.loading) {
    return <Spinner />;
  }

  if (state.failed) {
    return (
      <Alert variant="danger">
        {state.error}
        <Button onClick={() => actions.load(projectPath)}>Retry</Button>
      </Alert>
    );
  }

  if (!state.loaded || !state.value) {
    return <EmptyState>No features loaded</EmptyState>;
  }

  return (
    <KanbanBoard>
      {state.value.map((feature) => (
        <FeatureCard key={feature.id} feature={feature} />
      ))}
    </KanbanBoard>
  );
}
```

